input.command:
powershell -NoProfile -ExecutionPolicy Bypass -Command '
$basePath = "C:/Users/Administrator/Desktop/SHINJIN/1 CELL 조립 장비/PLC RAW/ST_XEC"
$outPath = "$basePath/VAR_GLOBAL_ALL.csv"

# 결과 저장 배열
$rows = [System.Collections.ArrayList]::new()

# 파일별 영역 구분
$files = @{
    "GVL_INTERNAL.st" = "M"
    "GVL_DATA.st"     = "D"
    "GVL_TIMER.st"    = "T"
    "GVL_HMI.st"      = "K"
}

# 변수 선언 라인 파싱 정규식
# 패턴: name : type [AT %addr]; (* comment *)
$regex = "^\s+(\S+)\s*:\s*(BOOL|INT|DINT|TON|TOF|TP)\s*(?:AT\s+(%\S+))?\s*;\s*(?:\(\*\s*(.*?)\s*\*\))?\s*$"

$counts = @{ M=0; D=0; T=0; K=0 }

foreach ($file in $files.Keys) {
    $area = $files[$file]
    $filePath = "$basePath/$file"
    $content = [System.IO.File]::ReadAllText($filePath, [System.Text.Encoding]::UTF8)
    $lines = $content -split "`n"

    foreach ($line in $lines) {
        $line = $line.TrimEnd("`r")
        if ($line -match $regex) {
            $name = $Matches[1]
            $type = $Matches[2]
            $atAddr = if ($Matches[3]) { $Matches[3] } else { "" }
            $comment = if ($Matches[4]) { $Matches[4].Trim() } else { "" }

            # XG5000 유효성: 디바이스 접두사로 시작하는 이름에 언더스코어 추가
            # M/K/P/D/T/U + 숫자만으로 구성된 이름 -> 앞에 _ 추가
            if ($name -match "^[MKPDTU]\d+$") {
                $name = "_$name"
            }

            # 주소 매핑 (AT 없는 경우)
            $address = $atAddr
            if ([string]::IsNullOrEmpty($address)) {
                if ($area -eq "M") {
                    # _Mxxxxx 또는 _M0xxxx -> hex -> decimal -> %MXddd
                    if ($name -match "^_M([0-9A-Fa-f]+)$") {
                        $hexStr = $Matches[1]
                        $dec = [Convert]::ToInt32($hexStr, 16)
                        $address = "%MX$dec"
                    }
                }
                elseif ($area -eq "D") {
                    # _Dxxxxx -> decimal number -> %MWnnn
                    if ($name -match "^_D(\d+)$") {
                        $num = [int]$Matches[1]
                        $address = "%MW$num"
                    }
                }
                elseif ($area -eq "K") {
                    # _Kxxxxx -> hex -> decimal -> %KXddd
                    if ($name -match "^_K([0-9A-Fa-f]+)$") {
                        $hexStr = $Matches[1]
                        $dec = [Convert]::ToInt32($hexStr, 16)
                        $address = "%KX$dec"
                    }
                }
                elseif ($area -eq "T") {
                    # 타이머는 메모리 주소 없음
                    $address = ""
                }
            }

            # CSV 행 생성
            # 변수 종류,이름,타입,메모리 할당,초기값,리테인,읽기 전용,EIP,OPC UA,HMI,축,디스크립션
            $csvLine = "VAR_GLOBAL,$name,$type,$address,,0,0,0,0,0,0,$comment"
            [void]$rows.Add($csvLine)
            $counts[$area]++
        }
    }
}

# 헤더 + 내용
$header = "변수 종류,이름,타입,메모리 할당,초기값,리테인,읽기 전용,EIP,OPC UA,HMI,축,디스크립션"
$csvContent = $header + "`r`n" + ($rows -join "`r`n") + "`r`n"

# CP949 인코딩으로 저장
$bytes = [System.Text.Encoding]::GetEncoding(949).GetBytes($csvContent)
[System.IO.File]::WriteAllBytes($outPath, $bytes)

# 결과 출력
Write-Host "=== VAR_GLOBAL_ALL.csv 생성 완료 ==="
Write-Host "파일: $outPath"
Write-Host "M area: $($counts["M"])"
Write-Host "D area: $($counts["D"])"
Write-Host "T area: $($counts["T"])"
Write-Host "K area: $($counts["K"])"
Write-Host "Total:  $($rows.Count)"
Write-Host ""
Write-Host "=== 처음 5줄 확인 ==="
Write-Host $header
$rows[0..4] | ForEach-Object { Write-Host $_ }
Write-Host ""
Write-Host "=== 마지막 5줄 확인 ==="
$rows[($rows.Count-5)..($rows.Count-1)] | ForEach-Object { Write-Host $_ }
'
